```typescript
class MinHeap<T extends [number, number, number]> {
    private heap: T[] = [];

    push(item: T): void {
        this.heap.push(item);
        this._bubbleUp(this.heap.length - 1);
    }

    pop(): T | undefined {
        if (this.heap.length === 0) return undefined;
        const top = this.heap[0];
        const last = this.heap.pop()!;
        if (this.heap.length > 0) {
            this.heap[0] = last;
            this._sinkDown(0);
        }
        return top;
    }

    private _bubbleUp(idx: number): void {
        const item = this.heap[idx];
        while (idx > 0) {
            const parentIdx = (idx - 1) >> 1;
            const parent = this.heap[parentIdx];
            if (item[0] >= parent[0]) break;
            this.heap[idx] = parent;
            idx = parentIdx;
        }
        this.heap[idx] = item;
    }

    private _sinkDown(idx: number): void {
        const length = this.heap.length;
        const item = this.heap[idx];
        while (true) {
            const leftIdx = 2 * idx + 1;
            const rightIdx = 2 * idx + 2;
            let swapIdx = leftIdx;
            if (leftIdx < length) {
                const left = this.heap[leftIdx];
                const right = this.heap[rightIdx];
                if (leftIdx < length && left[0] <= item[0]) {
                    if (rightIdx < length && right[0] < left[0]) {
                        swapIdx = rightIdx;
                    }
                } else if (rightIdx < length && right[0] < item[0]) {
                    swapIdx = rightIdx;
                } else {
                    break;
                }
            } else {
                break;
            }
            this.heap[idx] = this.heap[swapIdx];
            idx = swapIdx;
        }
        this.heap[idx] = item;
    }
}
```

